import React, { useRef } from "react";
import { motion, useInView } from "framer-motion";
import MasonryGrid from "./MasonryGrid";
import Wave from "../DecorationComponents/wavecircle.svg";

const Galeria = () => {
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true, amount: 0.3 });

  return (
    <section ref={ref} className="h-screen snap-start overflow-hidden relative bg-white flex flex-col justify-center">

      {/* SVG derecha */}
      <div className="pointer-events-none absolute inset-0 z-0 overflow-hidden">
        <motion.div
          className="absolute"
          style={{ top: '-60%', right: '-65vw' }}
          initial={{ opacity: 0, x: 200 }}
          animate={isInView ? { opacity: 1, x: 0 } : {}}
          transition={{ duration: 1, ease: "easeOut" }}
        >
          <img
            src={Wave}
            className="w-[120vw] animate-spin-slow"
            style={{ transformOrigin: 'center center' }}
          />
        </motion.div>
      </div>

      {/* SVG izquierda */}
      <div className="pointer-events-none absolute inset-0 z-0 overflow-hidden">
        <motion.div
          className="absolute"
          style={{ top: '-30%', left: '-50vw' }}
          initial={{ opacity: 0, x: -200 }}
          animate={isInView ? { opacity: 1, x: 0 } : {}}
          transition={{ duration: 1, ease: "easeOut" }}
        >
          <img
            src={Wave}
            className="w-[120vw] animate-spin-slow-reverse"
            style={{ transformOrigin: 'center center' }}
          />
        </motion.div>
      </div>

      {/* CONTENIDO */}
      <div className="relative z-10 text-center mb-[3vh]">
        <h1 className="titulo-playfair font-semibold text-[#7D6239] text-[2rem]">
          ¿Te quedaste con ganas de ver más?
        </h1>
        <div className="h-[5px] w-[3rem] mx-auto rounded-full bg-gradient-to-r from-[#CC2329] to-[#F55809]" />
      </div>

      <div className="relative z-10 w-[50%] mx-auto">
        <MasonryGrid />
      </div>

    </section>
  );
};

export default Galeria;
